#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long matrix[2][2];
long long result[2][2];

void multiply(long long a[2][2], long long b[2][2]) {
    long long c[2][2];
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            c[i][j] = 0;
            for (int k = 0; k < 2; k++) {
                c[i][j] += a[i][k] * b[k][j];
                c[i][j] %= MOD;
            }
        }
    }
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            a[i][j] = c[i][j];
        }
    }
}

void power(long long a[2][2], long long n) {
    if (n == 1) return;
    if (n % 2 == 0) {
        power(a, n / 2);
        multiply(a, a);
    } else {
        power(a, n / 2);
        multiply(a, a);
        multiply(a, matrix);
    }
}

